const now = new Date();
const rows = $input.all().map(item => item.json);
function isIslandCampaign(row) {
  return (row.campaign || '').toLowerCase() === 'rishiri_island' || (row.audience || '').toLowerCase() === 'island';
}
function afterIslandSeason(scheduled) {
  const month = scheduled.getMonth() + 1;
  const day = scheduled.getDate();
  return month > 9 || (month === 9 && day > 30);
}
function due(row) {
  if ((row.status || '').toLowerCase() !== 'approved') return false;
  if ((row.fact_check_status || '').toLowerCase() !== 'ok') return false;
  if (row.published_at_jst) return false;
  if (!row.scheduled_at_jst) return false;
  const scheduled = new Date(row.scheduled_at_jst.replace(' ', 'T') + '+09:00');
  if (isIslandCampaign(row) && afterIslandSeason(scheduled)) return false;
  return scheduled <= now;
}
return rows.filter(due).map(row => ({ json: row }));
